using System; using System.Collections.Generic; using System.Drawing; using System.Linq; using System.Windows.Forms; namespace btlwindow { public partial class ucReport : UserControl { public ucReport() { InitializeComponent(); } private void ucReport_Load(object sender, EventArgs e) { LoadReport(); } public void LoadReport() { List<TaskModel> tasks = TaskRepository.LoadTasks(); int total = tasks.Count; int todo = tasks.Count(t => t.TrangThai == "Todo"); int doing = tasks.Count(t => t.TrangThai == "Doing"); int done = tasks.Count(t => t.TrangThai == "Done"); int overdue = tasks.Count(t => t.IsOverdue); lblTotal.Text = "Tong cong viec: " + total; lblTodo.Text = "Can lam: " + todo; lblDoing.Text = "Dang lam: " + doing; lblDone.Text = "Da xong: " + done; lblOverdue.Text = "Qua han: " + overdue; if (total > 0) { double pct = (double)done / total * 100; lblProgress.Text = "Tien do: " + pct.ToString("F1") + "%"; prgProgress.Value = (int)pct; } else { lblProgress.Text = "Tien do: 0%"; prgProgress.Value = 0; } } } }